function debounce(func, delayMs) {
  let timerId; // Stored in closure

  return function(...args) {
    // Cancel the previous timer if it exists
    clearTimeout(timerId);

    // Start a brand new timer
    timerId = setTimeout(() => {
      func.apply(this, args);
    }, delayMs);
  };
}

// The heavy API call
function fetchSearchResults(query) {
  console.log('Fetching results for:', query);
}

// Create debounced version (waits 500ms after last keystroke)
const debouncedSearch = debounce(fetchSearchResults, 500);

// User types 'a', 'p', 'p', 'l', 'e' rapidly
debouncedSearch('a');    // Timer started
debouncedSearch('ap');   // Timer reset
debouncedSearch('app');  // Timer reset
debouncedSearch('appl'); // Timer reset
debouncedSearch('apple');// Timer reset
// ...user stops typing for 500ms...
// Output: Fetching results for: apple
